curl --http3 \
     --h3-priority u=3,i \
     -i \
     https://example.com

# Save headers to file
curl --http3 \
     --h3-priority u=2 \
     -D headers.txt \
     https://example.com
```

---

## Error Handling

### C API Error Handling

```c
#include <curl/curl.h>
#include <stdio.h>

int main(void) {
  CURL *curl = curl_easy_init();
  CURLcode res;

  if(curl) {
    struct curl_h3_stream_priority priority;

    /* Invalid urgency (>7) */
    priority.urgency = 8;  /* Error! */
    priority.incremental = 0;

    res = curl_easy_setopt(curl, CURLOPT_H3_STREAM_PRIORITY, &priority);

    if(res == CURLE_BAD_FUNCTION_ARGUMENT) {
      printf("Error: Invalid priority value\\n");
    }

    /* Correct usage */
    priority.urgency = 3;  /* OK */
    res = curl_easy_setopt(curl, CURLOPT_H3_STREAM_PRIORITY, &priority);

    if(res != CURLE_OK) {
      printf("Error: %s\\n", curl_easy_strerror(res));
    }

    curl_easy_cleanup(curl);
  }

  return 0;
}
```

### CLI Error Handling

```bash
# Invalid format (missing 'u=')
curl --http3 --h3-priority 3 https://example.com
# Error: Invalid priority format. Use: u=<0-7>[,i]

# Invalid urgency value (>7)
curl --http3 --h3-priority u=9 https://example.com
# Error: Invalid urgency value (must be 0-7): 9

# Correct usage
curl --http3 --h3-priority u=3,i https://example.com
# Works!
```

---

## Best Practices

1. **Critical Resources**: Use urgency 0-1 for blocking resources
2. **Normal Resources**: Use urgency 3 (default) for standard content
3. **Background**: Use urgency 6-7 for non-essential requests
4. **Incremental Flag**: Set for resources that can be rendered progressively
5. **Testing**: Always test with real HTTP/3 servers to verify impact
6. **Error Handling**: Always check return values from curl_easy_setopt()

---

## Verification

### Verify Priority Header Sent

```bash
# Using curl with verbose mode
curl --http3 --h3-priority u=0 -v https://example.com 2>&1 | grep -i priority

# Expected output should show:
# > priority: u=0
```

### Capture with tcpdump/Wireshark

```bash
# Capture HTTP/3 traffic
tcpdump -i eth0 -w http3.pcap udp port 443

# Then analyze in Wireshark to verify HEADERS frame contains Priority field
```

