    /* Set custom priority */
    priority.urgency = 2;
    priority.incremental = 1;
    curl_easy_setopt(curl, CURLOPT_H3_STREAM_PRIORITY, &priority);

    /* ... do some work ... */

    /* Reset to defaults by passing NULL */
    curl_easy_setopt(curl, CURLOPT_H3_STREAM_PRIORITY, NULL);

