### Scenario 2: API Client with Priority Levels

```c
#include <curl/curl.h>
#include <stdio.h>

typedef enum {
  PRIORITY_CRITICAL = 0,      /* Blocking operations */
  PRIORITY_HIGH = 1,          /* User-initiated requests */
  PRIORITY_NORMAL = 3,        /* Normal operations */
  PRIORITY_LOW = 5,           /* Prefetching */
  PRIORITY_BACKGROUND = 7     /* Batch/sync operations */
} RequestPriority;

CURL *create_http3_request(const char *url, RequestPriority priority) {
  CURL *curl = curl_easy_init();

  if(curl) {
    struct curl_h3_stream_priority p;
    p.urgency = (unsigned char)priority;
    p.incremental = (priority <= PRIORITY_NORMAL) ? 1 : 0;

    curl_easy_setopt(curl, CURLOPT_URL, url);
    curl_easy_setopt(curl, CURLOPT_HTTP_VERSION, CURL_HTTP_VERSION_3_0);
    curl_easy_setopt(curl, CURLOPT_H3_STREAM_PRIORITY, &p);
  }

  return curl;
}

int main(void) {
  /* Fetch user's immediate action */
  CURL *search = create_http3_request(
      "https://api.example.com/search?q=curl",
      PRIORITY_CRITICAL);
  curl_easy_perform(search);

  /* Prefetch next page (lower priority) */
  CURL *prefetch = create_http3_request(
      "https://api.example.com/search?q=curl&page=2",
      PRIORITY_LOW);
  curl_easy_perform(prefetch);

  /* Sync background data */
  CURL *sync = create_http3_request(
      "https://api.example.com/sync",
      PRIORITY_BACKGROUND);
  curl_easy_perform(sync);

  curl_easy_cleanup(search);
  curl_easy_cleanup(prefetch);
  curl_easy_cleanup(sync);

  return 0;
}
```

### Scenario 3: Batch Download with Priority Handling

```bash
#!/bin/bash

# Download assets with appropriate priorities
# Critical files first, then progressive loading

DOMAIN="https://cdn.example.com"
PRIORITY_CRITICAL="u=0"
PRIORITY_IMPORTANT="u=2"
PRIORITY_NORMAL="u=4,i"
PRIORITY_BACKGROUND="u=7"

# Critical: Metadata
curl --http3 --h3-priority $PRIORITY_CRITICAL \
     -O "$DOMAIN/manifest.json"

# Important: Core assets
curl --http3 --h3-priority $PRIORITY_IMPORTANT \
     -O "$DOMAIN/app.js" \
     -O "$DOMAIN/style.css"

# Normal: Media (incremental for streaming)
curl --http3 --h3-priority $PRIORITY_NORMAL \
     -O "$DOMAIN/banner.jpg" \
     -O "$DOMAIN/logo.png"

# Background: Non-essential
curl --http3 --h3-priority $PRIORITY_BACKGROUND \
     -O "$DOMAIN/analytics.js" \
     -O "$DOMAIN/ads.js"
```

